import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'sonner';
import { User, Mail, Lock, Eye, EyeOff } from 'lucide-react';

// SVG Logo MPL
const MPLLogo = () => (
  <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
    <rect width="40" height="40" rx="6" fill="#1a1a1a" stroke="#F5A623" strokeWidth="1.5"/>
    <text x="50%" y="55%" dominantBaseline="middle" textAnchor="middle"
      fill="#F5A623" fontSize="13" fontWeight="bold" fontFamily="Arial">MPL</text>
  </svg>
);

// SVG Hero Truck Illustration
const TruckHero = () => (
  <svg viewBox="0 0 800 600" xmlns="http://www.w3.org/2000/svg" className="w-full h-full">
    <defs>
      <linearGradient id="skyGrad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stopColor="#87CEEB"/>
        <stop offset="60%" stopColor="#FDB97D"/>
        <stop offset="100%" stopColor="#E8956D"/>
      </linearGradient>
      <linearGradient id="roadGrad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stopColor="#555"/>
        <stop offset="100%" stopColor="#333"/>
      </linearGradient>
    </defs>
    {/* Sky */}
    <rect width="800" height="600" fill="url(#skyGrad)"/>
    {/* Road */}
    <rect x="0" y="420" width="800" height="180" fill="url(#roadGrad)"/>
    {/* Road lines */}
    <rect x="0" y="500" width="160" height="8" fill="#fff" opacity="0.5"/>
    <rect x="220" y="500" width="160" height="8" fill="#fff" opacity="0.5"/>
    <rect x="440" y="500" width="160" height="8" fill="#fff" opacity="0.5"/>
    <rect x="660" y="500" width="160" height="8" fill="#fff" opacity="0.5"/>
    {/* Truck body */}
    <rect x="80" y="270" width="480" height="160" rx="4" fill="#e8e8e8" stroke="#ccc" strokeWidth="2"/>
    {/* Truck cabin */}
    <rect x="560" y="300" width="150" height="130" rx="8" fill="#D97706"/>
    {/* Cabin window */}
    <rect x="575" y="315" width="110" height="65" rx="4" fill="#87CEEB" opacity="0.8"/>
    {/* Cabin detail */}
    <rect x="560" y="380" width="150" height="20" fill="#b45309"/>
    {/* Wheels */}
    <circle cx="180" cy="435" r="35" fill="#222"/>
    <circle cx="180" cy="435" r="20" fill="#555"/>
    <circle cx="180" cy="435" r="8" fill="#888"/>
    <circle cx="330" cy="435" r="35" fill="#222"/>
    <circle cx="330" cy="435" r="20" fill="#555"/>
    <circle cx="330" cy="435" r="8" fill="#888"/>
    <circle cx="610" cy="435" r="35" fill="#222"/>
    <circle cx="610" cy="435" r="20" fill="#555"/>
    <circle cx="610" cy="435" r="8" fill="#888"/>
    <circle cx="690" cy="435" r="35" fill="#222"/>
    <circle cx="690" cy="435" r="20" fill="#555"/>
    <circle cx="690" cy="435" r="8" fill="#888"/>
    {/* Cargo door lines */}
    <line x1="280" y1="270" x2="280" y2="430" stroke="#ccc" strokeWidth="2"/>
    <line x1="80" y1="350" x2="560" y2="350" stroke="#ccc" strokeWidth="1.5"/>
    {/* Headlight */}
    <rect x="705" y="340" width="20" height="12" rx="3" fill="#FFF176"/>
    {/* Sun */}
    <circle cx="680" cy="100" r="55" fill="#FDB97D" opacity="0.8"/>
    {/* Buildings silhouette */}
    <rect x="0" y="320" width="60" height="100" fill="#666" opacity="0.4"/>
    <rect x="20" y="290" width="30" height="130" fill="#555" opacity="0.4"/>
    <rect x="730" y="330" width="70" height="90" fill="#666" opacity="0.4"/>
    <rect x="750" y="300" width="40" height="120" fill="#555" opacity="0.4"/>
  </svg>
);

const Register = () => {
  const navigate = useNavigate();
  const { register } = useAuth();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
  });

  const handleSubmit = (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      toast.error('Password dan konfirmasi password tidak cocok');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password minimal 6 karakter');
      return;
    }

    const result = register(formData.name, formData.email, formData.password, formData.phone);

    if (result.success) {
      toast.success('Registrasi berhasil! Selamat datang.');
      setTimeout(() => navigate('/'), 1000);
    } else {
      toast.error(result.message);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="h-screen overflow-hidden flex bg-[#0D0D0D]" data-testid="register-page">
      {/* Left — Hero Image */}
      <div className="hidden lg:block lg:w-3/5 relative p-4">
        <div className="relative w-full h-full rounded-2xl overflow-hidden border-2 border-blue-500">
          {/* Truck SVG as background */}
          <div className="absolute inset-0">
            <TruckHero />
          </div>
          {/* Dark overlay */}
          <div className="absolute inset-0 bg-black/30" />
          {/* Logo overlay */}
          <div className="absolute top-6 left-6 flex items-center gap-3 z-10">
            <MPLLogo />
            <span className="text-white font-bold text-xl tracking-widest uppercase drop-shadow">
              MANDIRI PERKASA
            </span>
          </div>
        </div>
      </div>

      {/* Right — Form Panel */}
      <div className="w-full lg:w-2/5 bg-[#0D0D0D] flex flex-col justify-center px-10 overflow-hidden">
        {/* Mobile logo */}
        <div className="flex items-center gap-3 mb-6 lg:hidden">
          <MPLLogo />
          <span className="text-white font-bold text-lg tracking-widest uppercase">
            MANDIRI PERKASA
          </span>
        </div>

        <h2 className="text-4xl font-bold text-[#F5A623] mb-1" data-testid="register-title">
          Daftar
        </h2>

        <p className="text-gray-400 text-sm mb-6 leading-relaxed">
          Jika Anda sudah memiliki akun, silakan mendaftar.
          <br />
          kamu dapat{' '}
          <Link
            to="/masuk"
            className="text-[#F5A623] font-semibold hover:underline"
            data-testid="login-link"
          >
            Masuk disini
          </Link>
        </p>

        <form onSubmit={handleSubmit} className="space-y-5">
          {/* Email */}
          <div>
            <label className="block text-sm font-semibold text-white mb-1">Email</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Mail className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="email"
                type="email"
                required
                value={formData.email}
                onChange={handleChange}
                placeholder="Masukan Email Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-email"
              />
            </div>
          </div>

          {/* Nama Pengguna */}
          <div>
            <label className="block text-sm font-semibold text-white mb-1">Nama Pengguna</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <User className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="name"
                type="text"
                required
                value={formData.name}
                onChange={handleChange}
                placeholder="Masukan Nama Pengguna"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-name"
              />
            </div>
          </div>

          {/* Kata Kunci */}
          <div>
            <label className="block text-sm font-semibold text-white mb-1">Kata Kunci</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Lock className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="password"
                type={showPassword ? 'text' : 'password'}
                required
                value={formData.password}
                onChange={handleChange}
                placeholder="Masukan Kata Sandi Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-password"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="ml-2 shrink-0"
                data-testid="toggle-password"
              >
                {showPassword ? (
                  <Eye className="h-4 w-4 text-gray-500" />
                ) : (
                  <EyeOff className="h-4 w-4 text-gray-500" />
                )}
              </button>
            </div>
          </div>

          {/* Konfirmasi Kata Sandi */}
          <div>
            <label className="block text-sm font-semibold text-white mb-1">
              Konfirmasi Kata Sandi
            </label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Lock className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="confirmPassword"
                type={showConfirm ? 'text' : 'password'}
                required
                value={formData.confirmPassword}
                onChange={handleChange}
                placeholder="Konfirmasi Kata Sandi Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-confirm-password"
              />
              <button
                type="button"
                onClick={() => setShowConfirm(!showConfirm)}
                className="ml-2 shrink-0"
              >
                {showConfirm ? (
                  <Eye className="h-4 w-4 text-gray-500" />
                ) : (
                  <EyeOff className="h-4 w-4 text-gray-500" />
                )}
              </button>
            </div>
          </div>

          {/* Submit */}
          <div className="pt-3">
            <button
              type="submit"
              className="w-full py-3 bg-[#F5A623] text-black font-bold text-base rounded-full hover:bg-[#e09518] transition-colors"
              data-testid="register-submit-button"
            >
              Daftar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Register;
